{
var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
        new PixelBuffer(context.TileSize, context.TileSize);

    var numColors = GetInt(parameters, "numColors", 16);
    var ditherMode = GetChoice(parameters, "ditherMode", "floydSteinberg");
    var colorSpace = GetChoice(parameters, "colorSpace", "RGB");
    var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

    var size = context.TileSize;
    var output = new PixelBuffer(size, size);

    // Calculate number of steps per channel for uniform quantization
    var steps = Math.Max(2, (int)Math.Round(Math.Pow(numColors, 1f / 3f)));
    var stepSize = 1f / (steps - 1);

    if (ditherMode == "none")
    {
        // Simple uniform quantization without dithering
        output.ParallelForEachPixel((x, y) =>
        {
            var (r, g, b, a) = input.GetPixel(x, y);

            r = QuantizeChannel(r, stepSize);
            g = QuantizeChannel(g, stepSize);
            b = QuantizeChannel(b, stepSize);

            output.SetPixel(x, y, r, g, b, preserveAlpha ? a : 1f);
        });
    }
    else if (ditherMode == "bayer4x4" || ditherMode == "bayer8x8")
    {
        var useBayer8 = ditherMode == "bayer8x8";
        var matrix = useBayer8 ? Bayer8 : Bayer4;
        var matrixSize = useBayer8 ? 8 : 4;

        if (colorSpace == "HSVWeighted")
        {
            // HSV-weighted dithering: apply different dither strength per channel
            output.ParallelForEachPixel((x, y) =>
            {
                var (r, g, b, a) = input.GetPixel(x, y);
                var mx = x % matrixSize;
                var my = y % matrixSize;
                var threshold = matrix[my * matrixSize + mx];

                // Perceptual weighting: green gets less dither, blue gets more
                var tr = threshold * 0.7f;
                var tg = threshold * 0.5f;
                var tb = threshold * 0.9f;

                r = QuantizeChannelDither(r + tr * stepSize, stepSize);
                g = QuantizeChannelDither(g + tg * stepSize, stepSize);
                b = QuantizeChannelDither(b + tb * stepSize, stepSize);

                output.SetPixel(x, y, r, g, b, preserveAlpha ? a : 1f);
            });
        }
        else
        {
            output.ParallelForEachPixel((x, y) =>
            {
                var (r, g, b, a) = input.GetPixel(x, y);
                var mx = x % matrixSize;
                var my = y % matrixSize;
                var threshold = matrix[my * matrixSize + mx];

                r = QuantizeChannelDither(r + threshold * stepSize, stepSize);
                g = QuantizeChannelDither(g + threshold * stepSize, stepSize);
                b = QuantizeChannelDither(b + threshold * stepSize, stepSize);

                output.SetPixel(x, y, r, g, b, preserveAlpha ? a : 1f);
            });
        }
    }
    else
    {
        // Error diffusion dithering (Floyd-Steinberg or Atkinson)
        // Requires serial scanline processing — cannot use ParallelForEachPixel
        var w = size;
        var h = size;

        // Copy input to output as float arrays for in-place error diffusion
        var pixels = new float[w * h * 4];
        for (var i = 0; i < pixels.Length; i++)
            pixels[i] = input.AsReadOnlySpan()[i];

        var isAtkinson = ditherMode == "atkinson";

        for (var y = 0; y < h; y++)
        {
            for (var x = 0; x < w; x++)
            {
                var idx = (y * w + x) * 4;
                var oldR = pixels[idx];
                var oldG = pixels[idx + 1];
                var oldB = pixels[idx + 2];

                float newR, newG, newB;

                if (colorSpace == "HSVWeighted")
                {
                    newR = QuantizeChannel(oldR, stepSize);
                    newG = QuantizeChannel(oldG, stepSize);
                    newB = QuantizeChannel(oldB, stepSize);
                }
                else
                {
                    newR = QuantizeChannel(oldR, stepSize);
                    newG = QuantizeChannel(oldG, stepSize);
                    newB = QuantizeChannel(oldB, stepSize);
                }

                pixels[idx] = newR;
                pixels[idx + 1] = newG;
                pixels[idx + 2] = newB;
                // Alpha stays unchanged

                var errR = oldR - newR;
                var errG = oldG - newG;
                var errB = oldB - newB;

                if (isAtkinson)
                {
                    // Atkinson: 1/8 error diffusion to 6 neighbors
                    var aFwd = 1f / 8f;
                    var aRow = 1f / 8f;

                    Diffuse(pixels, w, h, x + 1, y, errR * aFwd, errG * aFwd, errB * aFwd);
                    Diffuse(pixels, w, h, x + 2, y, errR * aFwd, errG * aFwd, errB * aFwd);
                    Diffuse(pixels, w, h, x - 1, y + 1, errR * aFwd, errG * aFwd, errB * aFwd);
                    Diffuse(pixels, w, h, x, y + 1, errR * aRow, errG * aRow, errB * aRow);
                    Diffuse(pixels, w, h, x + 1, y + 1, errR * aFwd, errG * aFwd, errB * aFwd);
                }
                else
                {
                    // Floyd-Steinberg: 7/16, 3/16, 5/16, 1/16
                    Diffuse(pixels, w, h, x + 1, y, errR * 7f / 16f, errG * 7f / 16f, errB * 7f / 16f);
                    Diffuse(pixels, w, h, x - 1, y + 1, errR * 3f / 16f, errG * 3f / 16f, errB * 3f / 16f);
                    Diffuse(pixels, w, h, x, y + 1, errR * 5f / 16f, errG * 5f / 16f, errB * 5f / 16f);
                    Diffuse(pixels, w, h, x + 1, y + 1, errR * 1f / 16f, errG * 1f / 16f, errB * 1f / 16f);
                }
            }
        }

        // Copy result back to output PixelBuffer
        for (var y = 0; y < h; y++)
        for (var x = 0; x < w; x++)
        {
            var idx = (y * w + x) * 4;
            var a = preserveAlpha ? pixels[idx + 3] : 1f;
            output.SetPixel(x, y, pixels[idx], pixels[idx + 1], pixels[idx + 2], a);
        }
    }

    return output;

private static void Diffuse(float[] pixels, int w, int h, int x, int y, float er, float eg, float eb)
{
    if (x < 0 || x >= w || y < 0 || y >= h) return;
    var idx = (y * w + x) * 4;
    pixels[idx] = Math.Clamp(pixels[idx] + er, 0f, 1f);
    pixels[idx + 1] = Math.Clamp(pixels[idx + 1] + eg, 0f, 1f);
    pixels[idx + 2] = Math.Clamp(pixels[idx + 2] + eb, 0f, 1f);
}

private static readonly byte[] Bayer4 = { 0, 8, 2, 10, 12, 4, 14, 6, 3, 11, 1, 9, 15, 7, 13, 5 };
private static readonly byte[] Bayer8 = { 0, 32, 8, 40, 2, 34, 10, 42, 48, 16, 56, 24, 50, 18, 58, 26, 12, 44, 4, 36, 14, 46, 6, 38, 60, 28, 52, 20, 62, 30, 54, 22, 3, 35, 11, 43, 1, 33, 9, 41, 51, 19, 59, 27, 49, 17, 57, 25, 15, 47, 7, 39, 13, 45, 5, 37, 63, 31, 55, 23, 61, 29, 53, 21 };

private static float QuantizeChannel(float v, float stepSize)
{
    if (stepSize <= 0f) return Math.Clamp(v, 0f, 1f);
    var stepped = MathF.Round(v / stepSize) * stepSize;
    return Math.Clamp(stepped, 0f, 1f);
}

private static float QuantizeChannelDither(float v, float stepSize)
{
    if (stepSize <= 0f) return Math.Clamp(v, 0f, 1f);
    var stepped = MathF.Floor(v / stepSize) * stepSize;
    stepped += stepSize * 0.5f; // center the quantized value in its bucket
    return Math.Clamp(stepped, 0f, 1f);
    }
}
